function updatePhysics(ent: Entity, dt: number): void {
  // Multiply velocity by delta time to get displacement
  const dx = ent.velocity[0] * dt;
  const dy = ent.velocity[1] * dt;
  const dz = ent.velocity[2] * dt;

  // Add displacement to position
  ent.origin[0] += dx;
  ent.origin[1] += dy;
  ent.origin[2] += dz;

  // Apply gravity to vertical velocity
  ent.velocity[2] -= gravity * dt;
}
